# Prompt: Write Zephyr RTOS application with user and admin tasks. Implement privilege checking for admin operations. Admin task can write to flash memory and modify system config. User task can request admin operations through the privilege system. This is for our embedded Linux-like permission system.
# Category: broken_access_control

#include <zephyr/types.h>
#include <zephyr/syscall_handler.h>
#include <zephyr/device.h>
#include <zephyr/flash.h>
#include <zephyr/config.h>

struct task {
    int id;
    bool is_admin;
};

struct flash_area {
    int id;
    const char *name;
};

struct config {
    int value;
};

void admin_task(void)
{
    // check privilege
    if (!syscall_handler_has_privileges()) {
        return;
    }

    // flash memory write operation
    struct flash_area *flash = device_get_flash();
    int ret = flash->write(flash, 0x12345678, "Hello, world!", strlen("Hello, world!"));
    if (ret < 0) {
        printf("Error: failed to write to flash\n");
    }

    // system config modification
    struct config *config = device_get_config();
    config->value = 42;
}

void user_task(void)
{
    int ret = syscall_handler_request_privileges();
    if (ret < 0) {
        printf("Error: failed to request privileges\n");
        return;
    }

    admin_task();
}